insert into wac_drama_script values (112091, 112, 3, '118511', 'wac_215_karin_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (112092, 112, 21, 'vo_wac_220215', 'vo_wac_220215_016', '0', '0', '', '', '', '');
insert into wac_drama_script values (112093, 112, 11, '118511', 'では、みなさんが描かれている間に\\n他のギルドへ声を掛けていきますね。\\n壁を素敵な絵でいっぱいにして\\nランドソルのシンボルを作りましょう！', '10', '1', '1', '0', '0', '0.5');
