insert into wac_drama_script values (212009, 212, 11, '105811', 'えっへへ～♪\u3000お絵かきお絵かき～！\\nこんな大きな絵を描くのなんて\\n生まれて初めてかもしれません！', '10', '1', '1', '0', '0', '0.5');
